OIDC_CONFIG = {
    "issuer": os.environ.get("OIDC_ISSUER", "https://accounts.google.com"),
    "client_id": os.environ.get("OIDC_CLIENT_ID", "your-client-id"),
    "client_secret": os.environ.get("OIDC_CLIENT_SECRET", "your-client-secret"),
    "redirect_uri": os.environ.get("OIDC_REDIRECT_URI", "http://localhost:5000/callback"),
    "scope": os.environ.get("OIDC_SCOPE", "openid email profile"),
}

# Cache for OIDC provider metadata and JWKS
_oidc_metadata = None
_jwks = None


def get_oidc_metadata():
    """Fetch and cache the OIDC provider's discovery document."""
    global _oidc_metadata
    if _oidc_metadata is None:
        discovery_url = f"{OIDC_CONFIG['issuer']}/.well-known/openid-configuration"
        response = requests.get(discovery_url, timeout=10)
        response.raise_for_status()
        _oidc_metadata = response.json()
    return _oidc_metadata


def get_jwks():
    """Fetch and cache the OIDC provider's JSON Web Key Set."""
    global _jwks
    if _jwks is None:
        metadata = get_oidc_metadata()
        jwks_uri = metadata["jwks_uri"]
        response = requests.get(jwks_uri, timeout=10)
        response.raise_for_status()
        _jwks = response.json()
    return _jwks


def decode_id_token(id_token):
    """Decode and verify the id_token using the provider's JWKS."""
    jwks = get_jwks()
    metadata = get_oidc_metadata()

    # Get the unverified header to find the key ID
    unverified_header = jwt.get_unverified_header(id_token)
    kid = unverified_header.get("kid")

    # Find the matching key
    rsa_key = None
    for key in jwks.get("keys", []):
        if key.get("kid") == kid:
            rsa_key = key
            break

    if rsa_key is None:
        # Refresh JWKS in case keys were rotated
        global _jwks
        _jwks = None
        jwks = get_jwks()
        for key in jwks.get("keys", []):
            if key.get("kid") == kid:
                rsa_key = key
                break

    if rsa_key is None:
        raise JWTError("Unable to find matching key in JWKS")

    # Decode and verify the token
    claims = jwt.decode(
        id_token,
        rsa_key,
        algorithms=["RS256"],
        audience=OIDC_CONFIG["client_id"],
        issuer=metadata["issuer"],
        options={
            "verify_at_hash": False,
        },
    )
    return claims


def login_required(f):
    """Decorator to require authentication for a route."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "user" not in session:
            session["next_url"] = request.url
            return redirect(url_for("login"))
        g.user = session["user"]
        return f(*args, **kwargs)
    return decorated_function


