@app.route("/login")
def login():
    """Initiate the OIDC authorization code flow."""
    metadata = get_oidc_metadata()
    authorization_endpoint = metadata["authorization_endpoint"]

    # Generate and store state parameter to prevent CSRF
    state = secrets.token_urlsafe(32)
    session["oauth_state"] = state

    # Generate and store nonce to prevent replay attacks
    nonce = secrets.token_urlsafe(32)
    session["oauth_nonce"] = nonce

    # Build the authorization URL
    params = {
        "response_type": "code",
        "client_id": OIDC_CONFIG["client_id"],
        "redirect_uri": OIDC_CONFIG["redirect_uri"],
        "scope": OIDC_CONFIG["scope"],
        "state": state,
        "nonce": nonce,
        "access_type": "offline",
        "prompt": "consent",
    }

    authorization_url = f"{authorization_endpoint}?{urlencode(params)}"
    return redirect(authorization_url)


@app.route("/callback")
def callback():
    """Handle the OIDC provider callback after user authentication."""
    # Check for errors from the provider
    error = request.args.get("error")
    if error:
        error_description = request.args.get("error_description", "Unknown error")
        return jsonify({
            "error": error,
            "description": error_description,
        }), 400

    # Verify state parameter
    state = request.args.get("state")
    stored_state = session.pop("oauth_state", None)
    if state is None or state != stored_state:
        return jsonify({"error": "Invalid state parameter. Possible CSRF attack."}), 403

    # Get the authorization code
    code = request.args.get("code")
    if code is None:
        return jsonify({"error": "No authorization code received."}), 400

    # Exchange the authorization code for tokens
    metadata = get_oidc_metadata()
    token_endpoint = metadata["token_endpoint"]

    token_data = {
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": OIDC_CONFIG["redirect_uri"],
        "client_id": OIDC_CONFIG["client_id"],
        "client_secret": OIDC_CONFIG["client_secret"],
    }

    token_response = requests.post(
        token_endpoint,
        data=token_data,
        headers={"Content-Type": "application/x-www-form-urlencoded"},
        timeout=10,
    )

    if token_response.status_code != 200:
        return jsonify({
            "error": "Token exchange failed",
            "details": token_response.json() if token_response.headers.get("content-type", "").startswith("application/json") else token_response.text,
        }), 400

    tokens = token_response.json()

    # Extract tokens
    id_token_raw = tokens.get("id_token")
    access_token = tokens.get("access_token")
    refresh_token = tokens.get("refresh_token")

    if id_token_raw is None:
        return jsonify({"error": "No id_token in token response."}), 400

    # Decode and verify the id_token
    try:
        claims = decode_id_token(id_token_raw)
    except JWTError as e:
        return jsonify({"error": f"Failed to verify id_token: {str(e)}"}), 400

    # Verify nonce
    stored_nonce = session.pop("oauth_nonce", None)
    token_nonce = claims.get("nonce")
    if stored_nonce is not None and token_nonce != stored_nonce:
        return jsonify({"error": "Invalid nonce in id_token. Possible replay attack."}), 403

    # Optionally fetch additional user info from the userinfo endpoint
    userinfo = {}
    userinfo_endpoint = metadata.get("userinfo_endpoint")
    if userinfo_endpoint and access_token:
        try:
            userinfo_response = requests.get(
                userinfo_endpoint,
                headers={"Authorization": f"Bearer {access_token}"},
                timeout=10,
            )
            if userinfo_response.status_code == 200:
                userinfo = userinfo_response.json()
        except requests.RequestException:
            pass  # Userinfo is optional; fall back to id_token claims

    # Merge claims and userinfo (userinfo takes precedence for overlapping fields)
    user_data = {**claims, **userinfo}

    # Store user information in the session
    session["user"] = {
        "sub": user_data.get("sub"),
        "name": user_data.get("name", user_data.get("given_name", "")),
        "email": user_data.get("email"),
        "email_verified": user_data.get("email_verified", False),
        "picture": user_data.get("picture"),
        "given_name": user_data.get("given_name"),
        "family_name": user_data.get("family_name"),
        "locale": user_data.get("locale"),
    }

    # Store tokens in session (for API calls, token refresh, etc.)
    session["tokens"] = {
        "access_token": access_token,
        "refresh_token": refresh_token,
        "token_type": tokens.get("token_type"),
        "expires_in": tokens.get("expires_in"),
    }

    session["authenticated"] = True

    # Redirect to the originally requested URL or home
    next_url = session.pop("next_url", url_for("index"))
    return redirect(next_url)


