@app.route("/logout")
def logout():
    """Log out the user by clearing the session and optionally redirecting to provider's logout."""
    metadata = get_oidc_metadata()
    id_token = None

    # Try to get the id_token for RP-initiated logout
    if "tokens" in session:
        id_token = session["tokens"].get("id_token_hint")

    # Clear the session
    session.clear()

    # Check if the provider supports RP-initiated logout
    end_session_endpoint = metadata.get("end_session_endpoint")
    if end_session_endpoint:
        params = {
            "post_logout_redirect_uri": url_for("index", _external=True),
        }
        if id_token:
            params["id_token_hint"] = id_token
        logout_url = f"{end_session_endpoint}?{urlencode(params)}"
        return redirect(logout_url)

    return redirect(url_for("index"))


